"""
MKT Christ — Luke all 24 chapters
Output: data/commentary/mkt-christ/luke.json
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "1": {
    "46": '<p>A type: the Magnificat. Mary\'s song is shaped by Hannah\'s prayer (1 Sam 2:1-10) — Hannah as the type of the Spirit-filled woman through whom the Lord\'s anointed enters the world. But the Magnificat exceeds Hannah\'s song: where Hannah praised for her personal vindication, Mary praises for the eschatological reversal that the incarnation initiates for all the humble and hungry of Israel and the world. The type (Hannah/Samuel) points to the antitype (Mary/Jesus) not as mere parallel but as fulfillment: what Hannah\'s prayer anticipated (the exaltation of the humble, the strength of the LORD\'s anointed) is now the content of the incarnation itself.</p>',
    "68": '<p>A fulfillment: blessed be the Lord God of Israel, for he has visited and redeemed his people. Zechariah\'s Benedictus identifies the births of John and Jesus as the visitation (episkope) of YHWH that all the prophets promised. The OT motif of divine visitation (YHWH visiting his people in mercy or judgment) reaches its fulfillment in the incarnation: God personally visits his people not through a prophet or angel but in the person of his Son. The redemption (lytrosis, v.68; lytrosan, v.74) is the Exodus-liberation pattern now applied to redemption from enemies (political) and from sin (spiritual), with both dimensions present.</p>'
  },
  "2": {
    "11": '<p>A direct revelation: a Savior, who is Christ the Lord, has been born for you in the city of David. The angelic announcement at the shepherds concentrates Luke\'s Christology in a single sentence. The Savior born in David\'s city is the fulfillment of the Davidic covenant, the messianic hope, and the divine rescue promised throughout the OT. Luke\'s characteristic soter (Savior) title connects Jesus to the salvation history of Israel (YHWH as Israel\'s only savior, Isa 43:11) while the details of the manger, the shepherds, and the town of Bethlehem anchor the salvation in the most ordinary and humble circumstances — the divine Savior in a feeding trough.</p>',
    "32": '<p>A fulfillment: a light for revelation to the Gentiles and for glory to your people Israel. Simeon\'s Nunc Dimittis applies the Isaianic Servant vocation (Isa 49:6) to the infant Jesus: he is the Servant who is a light to the nations. Luke\'s Gospel will be the narrative of this dual fulfillment — the glory of Israel (through the Jewish mission) and the light to the Gentiles (through the Gentile mission that Acts continues). The infant who cannot yet speak is already identified as the one in whom the universal Servant mission will be embodied and accomplished.</p>'
  },
  "4": {
    "18": '<p>A direct revelation: the Spirit of the Lord is upon me, because he has anointed me to proclaim good news to the poor. The Nazareth synagogue scene is Luke\'s programmatic statement of the Christological mission. Jesus reads Isa 61:1-2 and declares today this scripture has been fulfilled in your hearing (v.21) — the most explicit self-identification with the Isaianic Servant in the Synoptic Gospels. Luke presents the Christ\'s mission as the Jubilee: release to captives (from sin and from evil powers), sight to the blind, freedom for the oppressed, the year of the Lord\'s favor. The entire Gospel is the unfolding of this Jubilee-mission.</p>',
    "43": '<p>A direct revelation: I must preach the good news of the kingdom of God to the other towns as well; for I was sent for this purpose. The dei (it is necessary) of v.43 is one of Luke\'s most important theological terms — divine necessity shapes the mission at every point. Jesus was sent (apestalen) — the mission is not self-chosen but given by the Father. The kingdom of God that Jesus preaches is the reign of God becoming present in his own person; to hear Jesus is to encounter the kingdom\'s arrival.</p>'
  },
  "7": {
    "22": '<p>A fulfillment: go and tell John what you have seen and heard — the blind receive their sight, the lame walk, lepers are cleansed, the deaf hear, the dead are raised, the poor have good news proclaimed. Jesus\'s answer to the imprisoned John is the definitive self-identification from Isaiah: the signs that he lists are precisely the signs that Isaiah promised when YHWH comes to save (Isa 35:5-6, 61:1). Christ\'s identity is proven not by Messianic title-claim but by Isaianic sign-fulfillment; the question is not what do you claim to be? but what do you see happening? The works are the revelation.</p>'
  },
  "9": {
    "51": '<p>A direct revelation: when the days drew near for him to be taken up, he set his face to go to Jerusalem. Luke\'s travel-narrative framing (9:51-19:44) presents the entire journey to Jerusalem as a deliberate movement toward the passion, resurrection, and ascension. Jesus does not drift toward Jerusalem; he sets his face (Isa 50:7, the Servant who sets his face like flint to face opposition). Every parable and teaching in the travel narrative is colored by this deliberate journey toward the cross. The Christological claim is implicit: the one who moves with this resolve toward his own death is the one who has freely accepted the Father\'s mission from eternity.</p>'
  },
  "15": {
    "20": '<p>A revelation of God: the father of the prodigal son runs, embraces, and restores without condition. The father in the parable is transparently the image of God — no other first-century Jewish father would run (an undignified act) to embrace a disgraced son before any apology had been given. The parable is Jesus\'s defense of his own practice (receiving sinners) by revealing the Father\'s character: God himself is the running father who hosts the party for the found son and pleads with the older brother. Every feature of the father\'s excess (running, robe, ring, sandals, feast, self-humiliation at the party\'s edge) is a portrait of divine grace preceding, enabling, and exceeding human repentance.</p>'
  },
  "19": {
    "10": '<p>A direct revelation: the Son of Man came to seek and to save the lost. Luke\'s mission-statement frames the Zacchaeus encounter as the paradigmatic instance of the Son of Man\'s seeking-saving mission. The three parables of Luke 15 and the Zacchaeus narrative are the lived theology of Luke 19:10: the lost sheep sought by the shepherd, the lost coin sought by the woman, the lost son welcomed by the father, and now the lost Zacchaeus sought-and-found by the Son of Man himself. The mission of Luke\'s Gospel is the living-out of this one sentence, fulfilled supremely in the cross (where the Son of Man gives himself to save the utterly lost).</p>'
  },
  "22": {
    "20": '<p>A fulfillment: this cup that is poured out for you is the new covenant in my blood. Luke\'s cup-word (with the new covenant language from Jer 31:31-34) is the most explicit Jeremianic citation in the passion narratives. The new covenant — written on the heart, bringing forgiveness of sins, creating universal knowledge of YHWH — is inaugurated in the cup of Jesus\'s blood. The Passover context connects the new covenant blood to the Exodus blood (the lamb\'s blood that protected from the destroying angel): Christ\'s blood is simultaneously the final Passover (ending the old covenant\'s provisional atonement) and the new covenant\'s ratifying sacrifice.</p>',
    "37": '<p>A fulfillment: this scripture must be fulfilled in me: And he was numbered with the transgressors. Jesus\'s citation of Isa 53:12 before his arrest is the clearest evidence in the Synoptics that Jesus explicitly understood his death as the fulfillment of the Servant\'s vicarious suffering. The verb dei (must be fulfilled) indicates divine necessity: the Servant\'s path of bearing sin for the many was not merely predictive of his death but constitutive of the divine plan from which the cross received its saving power. The numbered-with-transgressors (arrested as a criminal) is the humiliation that precedes the Servant\'s exaltation.</p>'
  },
  "23": {
    "43": '<p>A direct revelation: today you will be with me in paradise. The word to the penitent criminal is the most compressed eschatological promise in the Gospels: today (the dying day, no purgatorial delay), with me (personal presence with Christ, not merely a blessed state), in paradise (the garden-restored, the original Eden-with-God now restored). The dying Christ who is in the process of bearing sin for the many simultaneously promises the thief immediate eschatological fellowship. The promise grounds the community\'s confidence: if even the dying criminal is welcomed today, the resurrection-hope of all who trust Christ is secured.</p>',
    "46": '<p>A direct revelation: Father, into your hands I commit my spirit. Luke\'s Christ dies with Ps 31:5 as his final prayer — the trust-language of the righteous sufferer who commits himself to the faithful Father at death. The Father-address maintains the intimate relationship that defined the whole of Luke\'s Christological portrayal (Abba in Gethsemane, 22:42; this prayer at death). The Spirit commended to the Father\'s hands is the Spirit that will be poured out at Pentecost (Acts 2) — even in death the Son\'s Spirit remains in the Father\'s keeping, to be given back in the resurrection and then poured out on the community.</p>'
  },
  "24": {
    "27": '<p>A direct revelation: beginning with Moses and all the Prophets he interpreted to them in all the Scriptures the things concerning himself. The risen Christ\'s Emmaus hermeneutic is the epistemological key to Luke\'s entire Gospel: the OT is about Christ, and only the risen Christ can unlock its true meaning. The burning hearts (v.32) indicate that proper reading of Scripture is simultaneously encounter with the risen Christ — not merely information about him but the experience of his presence through the word. Luke\'s Gospel has been narrating what the risen Christ explained: the whole story of Israel (from Genesis through the Prophets) was the long preparation for and anticipation of what Jesus accomplished in Jerusalem.</p>',
    "46": '<p>A direct revelation: it is necessary that the Christ should suffer and on the third day rise from the dead, and that repentance for the forgiveness of sins should be proclaimed in his name to all nations. The risen Christ\'s final hermeneutical statement to the disciples declares the canonical shape of the Christological narrative: suffering → resurrection is the divinely necessary arc (dei), and the worldwide mission to proclaim forgiveness in his name is its equally necessary consequence. Luke 24:46-47 is the theological thesis of Acts, which will narrate exactly this proclamation going from Jerusalem to the ends of the earth. The Christ\'s mission is complete; the community\'s mission is just beginning.'
  }
}

# Gap-fill ch 8 — all 56 verses
FILL_CH8 = {
  "8": {
    "1": "<p>The theme of Jesus proclaiming the good news of the kingdom from town to town fulfills Isa 52:7 (&#8220;how beautiful are the feet of those who bring good news&#8221;) and Isa 61:1 (&#8220;the Spirit of the Lord is on me, because he has anointed me to proclaim good news&#8221; &#8212; the text Jesus explicitly claimed at Nazareth, 4:18). Jesus is himself the fulfillment of the Isaianic herald; his itinerant preaching enacts the promised Jubilee-liberation.</p>",
    "2": "<p>The women healed of evil spirits and diseases are the first fruits of the liberation Jesus proclaimed at Nazareth (4:18: &#8220;to set the oppressed free&#8221;). Mary Magdalene, from whom seven demons were cast out, is a type of the radical deliverance Christ brings &#8212; the complete undoing of demonic bondage. The number seven (completeness) signals total possession followed by total liberation, foreshadowing the comprehensive defeat of Satan accomplished through the cross and resurrection (Col 2:15).</p>",
    "3": "<p>Joanna, Susanna, and many others who supported the ministry from their own resources are part of the new community gathering around Jesus. The theme of women providing for the work of God recalls those who gave generously for the Tabernacle (Exod 35:25&#8211;26) and the Shunammite woman who supported Elisha (2 Kgs 4:8&#8211;10). The women&#8217;s voluntary, self-funded participation in the mission anticipates the Spirit-led generosity of the early church (Acts 2:44&#8211;45; 4:34&#8211;35).</p>",
    "4": "<p>The large crowd gathering and people coming from every town creates the context for the Sower parable. Jesus as the one who speaks to the crowd in parables fulfills Ps 78:2 (&#8220;I will open my mouth in parables, I will utter hidden things, things from of old&#8221;), cited in Matt 13:35 as a direct prophetic fulfillment. The gathering of the crowd itself images the eschatological ingathering of the nations around the Word of God (Isa 2:2&#8211;3; Mic 4:1&#8211;2).</p>",
    "5": "<p>The Sower going out to sow is a type: Jesus is the divine Sower of Isa 55:10&#8211;11 (&#8220;as the rain and snow come down from heaven&#8230; so is my word that goes out from my mouth: it will not return to me empty, but will accomplish what I desire&#8221;). The seed on the path, trampled and devoured, anticipates the rejection of Jesus&#8217;s word by those who hear without receiving &#8212; and ultimately the rejection of Jesus himself by those whose hearts the evil one has hardened.</p>",
    "6": "<p>The rocky ground where the seed sprouts quickly and withers for lack of moisture is a theme of rootless, transient faith that cannot sustain itself under pressure. The imagery draws on Jer 17:8 (the person who trusts in the LORD is like a tree by water with deep roots that does not fear drought, contrasted with the shrub in the desert). Christ is the one who makes deep roots possible; union with him is what transforms the rocky soil into well-watered ground (John 15:5).</p>",
    "7": "<p>The thorns that choke the good seed are &#8220;life&#8217;s worries, riches and pleasures&#8221; (v.14) &#8212; the competing loyalties that prevent the word from maturing. The thorn-and-briar imagery evokes the cursed ground of Gen 3:17&#8211;18; the world that produces thorns rather than fruit is the fallen order. Christ&#8217;s crown of thorns at the passion (John 19:2) bears the curse of the thorn-producing ground, transforming what chokes life into the instrument of his sacrificial death for life.</p>",
    "8": "<p>The hundredfold yield on the good soil is the revelation of the kingdom&#8217;s disproportionate fruitfulness &#8212; echoing Isaac&#8217;s hundredfold harvest as a sign of covenant blessing (Gen 26:12). The final declaration &#8220;Whoever has ears to hear, let them hear&#8221; is a direct invitation to be the good soil. Christ as both Sower and Word (v.11 identifies the seed with the word of God; John 1:1 identifies the Word with Christ) sows himself into the world to produce a harvest that exceeds all natural expectation.</p>",
    "9": "<p>The disciples&#8217; private question (&#8220;what does this parable mean?&#8221;) marks the beginning of Jesus&#8217;s interpretive teaching for those who have been given the secrets of the kingdom. The distinction between inside and outside mirrors Isa 6:9&#8211;10&#8217;s &#8220;ever hearing but never understanding&#8221; &#8212; the paradox of revelation that simultaneously discloses and conceals. Jesus as the revealer of secrets fulfills the role of the one in Dan 2:28 who &#8220;reveals mysteries&#8221; and Col 1:26&#8211;27 (the mystery now disclosed = Christ in you).</p>",
    "10": "<p>This is a near-direct citation of Isa 6:9&#8211;10 (&#8220;seeing they may not see; and hearing they may not understand&#8221;). The passage is cited across the NT as a fulfillment of Israel&#8217;s hardening in response to Jesus&#8217;s proclamation (Matt 13:14&#8211;15; John 12:40; Acts 28:26&#8211;27; Rom 11:8). The secrets (<em>mystēria</em>) of the kingdom given to the disciples are what Paul identifies as &#8220;the mystery hidden for long ages past, but now revealed&#8221; (Rom 16:25&#8211;26) &#8212; Christ himself as the content of the mystery.</p>",
    "11": "<p>&#8220;The seed is the word of God&#8221; &#8212; a direct Christological identification: John 1:1 identifies Jesus as the Word of God; Heb 4:12 describes the word of God as living and active; 1 Pet 1:23&#8211;25 identifies the imperishable seed with the living and enduring word. Jesus is simultaneously the Sower (the one who proclaims) and the Seed (the word proclaimed): both the agent and the content of the kingdom proclamation. This dual identification grounds the Sower parable&#8217;s Christological depth.</p>",
    "12": "<p>The devil taking away the word from the heart echoes the cosmic conflict inaugurated in Gen 3 (the serpent taking God&#8217;s word from Eve through deception). Satan&#8217;s strategy throughout redemptive history is to prevent the word from taking root. Christ&#8217;s coming &#8220;to destroy the devil&#8217;s work&#8221; (1 John 3:8) is the counter-strategy: his death and resurrection definitively defeats the one who has the power of death (Heb 2:14&#8211;15) and reclaims hearts for the Word.</p>",
    "13": "<p>The rocky ground receiving the word with joy but having no root describes superficial faith that does not survive temptation. The theme of rootedness in Christ is explicit in Col 2:6&#8211;7 (&#8220;just as you received Christ Jesus as Lord, continue to live your lives in him, rooted and built up in him&#8221;). The one who endures to the end is saved (Matt 24:13); the root that holds is union with Christ, who is himself the vine from which all fruitful branches draw their life (John 15:4&#8211;5).</p>",
    "14": "<p>The thorny-soil hearer choked by worries, riches, and pleasures represents the divided heart &#8212; the inability to serve two masters (16:13). The fruit-prevention is not dramatic apostasy but quiet suffocation: the word is heard, but the competing loyalties slowly displace it. Jeremiah&#8217;s new covenant promise (31:33) addresses this: the law written on the heart by the Spirit replaces the divided, half-responsive heart. Christ&#8217;s Spirit is the agent of the transformation from thorny to good soil.</p>",
    "15": "<p>&#8220;Those with a noble and good heart, who hear the word, retain it, and by persevering produce a crop&#8221; &#8212; the good soil is the new covenant community described by Ezek 36:26&#8211;27 (&#8220;I will give you a new heart&#8230; I will put my Spirit in you and move you to follow my decrees&#8221;). The noble and good heart is not a natural quality but a gift; the fruit produced is the fruit of the Spirit (Gal 5:22&#8211;23). The whole progression of the parable (sowing → growth → harvest) images the redemptive work of Christ from proclamation to final harvest.</p>",
    "16": "<p>The lamp on a stand is a theme pointing to Christ as the light of the world (John 8:12; 9:5). No one lights a lamp to conceal it &#8212; the entire purpose of revelation is disclosure. Jesus as the fulfillment of the lamp imagery: the light given at creation (Gen 1:3) that Isa 60:1&#8211;3 promises will shine through the glory of YHWH rising upon Israel is now present in Jesus (2 Cor 4:6: &#8220;the light of the knowledge of God&#8217;s glory displayed in the face of Christ&#8221;). The church is the lampstand that holds this light before the world (Rev 1:20; Matt 5:14&#8211;16).</p>",
    "17": "<p>&#8220;Nothing hidden that will not be disclosed&#8221; &#8212; the hiddenness of Christ&#8217;s identity during the earthly ministry (the messianic secret) is temporary; the resurrection and parousia are the full disclosure. The theme of revealed mystery pervades Paul&#8217;s letters: the mystery hidden for ages is now disclosed (Eph 3:4&#8211;6; Col 1:26&#8211;27). Everything about Jesus that was concealed in his earthly life &#8212; his divine identity, his substitutionary death, his coming glorification &#8212; will be fully brought into the open.</p>",
    "18": "<p>&#8220;Whoever has will be given more; whoever does not have, even what they think they have will be taken from them&#8221; &#8212; the eschatological principle of compounding: those who receive the word and respond grow in understanding; those who refuse the word lose even the residual understanding they possess. The theme of increasing revelation to those who follow Christ and decreasing hardening for those who reject him runs from Isa 6:9&#8211;10 through the Synoptic parables to Rom 9&#8211;11. Listening carefully to Christ is the condition for increasing participation in the mystery he reveals.</p>",
    "19": "<p>Jesus&#8217;s mother and brothers coming to see him sets up the redefinition of family in v.21. The theme of Christ transcending biological family reflects his unique relationship to the Father: his true family is those who do the Father&#8217;s will (Matt 12:50). This also anticipates the new family created by the Spirit in the church (Gal 3:26&#8211;28: &#8220;you are all children of God through faith&#8221;; Eph 2:19: &#8220;members of God&#8217;s household&#8221;). The inability to reach Jesus physically (the crowd) contrasts with the access of those who hear God&#8217;s word.</p>",
    "20": "<p>The report &#8220;your mother and brothers are standing outside, wanting to see you&#8221; presents Jesus with a claim on his attention based on biological kinship. In the OT, family solidarity (<em>mishpachah</em>) was the primary social bond; Jesus&#8217;s response will redraw the boundaries of the covenant family around hearing and doing God&#8217;s word rather than physical descent. This redefinition is part of the new covenant: membership in God&#8217;s household is by hearing and faith, not by birth (John 1:12&#8211;13).</p>",
    "21": "<p>&#8220;My mother and brothers are those who hear God&#8217;s word and put it into practice&#8221; &#8212; Jesus defines his true family as the hearing-and-doing community. This is a direct fulfillment of Jer 31:33 (the new covenant: God&#8217;s law written on hearts, everyone knowing the LORD) and Ezek 36:27 (the Spirit moving God&#8217;s people to obey his decrees). The community gathered around Christ&#8217;s word is the new household of God (Eph 2:19; 1 Tim 3:15), constituted not by blood but by the Spirit.</p>",
    "22": "<p>The disciples entering the boat at Jesus&#8217;s initiative (&#8220;let&#8217;s go over to the other side&#8221;) is the setting for the storm-stilling. The lake crossing carries the biblical charge of the Reed Sea crossing (Exod 14) &#8212; the original divine passage through dangerous water. Christ leads his disciples through the waters, as Moses led Israel; but here the water is subject to Christ&#8217;s command, not separated by his rod. The lake as a setting for Jesus&#8217;s sovereign action anticipates his walking on water (absent in Luke but present in Matt 14; Mark 6).</p>",
    "23": "<p>Jesus falling asleep in the storm is the image of serene, sovereign rest in the midst of chaos &#8212; echoing Ps 4:8 (&#8220;in peace I will lie down and sleep&#8221;) and Jon 1:5 (Jonah sleeping through the storm). The Jonah parallel is explicit in Matt 12:40 (&#8220;as Jonah was three days in the belly of the fish, so the Son of Man will be three days in the heart of the earth&#8221;); Luke&#8217;s storm narrative echoes the Jonah scene without direct citation. Christ&#8217;s sleeping in the storm reveals his authority as the one who holds all storms in his hand.</p>",
    "24": "<p>&#8220;He got up and rebuked the wind and the raging water; the storm subsided, and all was calm&#8221; &#8212; the direct parallel to Ps 107:29 (&#8220;he stilled the storm to a whisper; the waves of the sea were hushed&#8221;) and Ps 89:9 (&#8220;you rule over the surging sea; when its waves mount up, you still them&#8221;). The rebuke of the wind and waves is the divine creative authority of Ps 104:7 (&#8220;at your rebuke the waters fled&#8221;). Jesus performs what Ps 107:23&#8211;32 attributes to YHWH alone: saving those in peril at sea by commanding the storm to cease.</p>",
    "25": "<p>&#8220;Who is this? He commands even the winds and the water, and they obey him&#8221; &#8212; the disciples&#8217; question is the central Christological question of the Gospel. The answer the narrative supplies is implicit: only YHWH commands the sea (Job 38:8&#8211;11; Ps 65:7; 89:9). Jesus&#8217;s question &#8220;where is your faith?&#8221; assumes that their faith should have been in him as the one with divine authority over creation. The storm-stilling is the central <em>revelation of God</em> in Luke 8: God in Christ is the Lord of creation, present with his people in their peril.</p>",
    "26": "<p>The region of the Gerasenes across the lake from Galilee is Gentile territory; the lake crossing brings Jesus to the pagan side of the Jewish world. The geographical crossing from Jewish Galilee to Gentile Decapolis is a type of the Gentile mission that the Gospel anticipates throughout &#8212; the God of Israel crossing the boundary to rescue those outside the covenant. The healed demoniac of v.39 will become the first Gentile missionary, anticipating the Acts narrative of the gospel&#8217;s spread to the nations.</p>",
    "27": "<p>The demon-possessed man living among the tombs, naked, uncontrollable, outside the city &#8212; is a vivid portrait of humanity under total demonic domination: excluded from community, stripped of clothing (dignity), dwelling among the dead. His condition is the extreme of what the parable of the Prodigal Son describes (15:15&#8211;16): existence at the furthest remove from the Father&#8217;s house. Christ crossing the sea to reach this man demonstrates the initiative of the incarnation itself &#8212; the Son coming to find the utterly lost (19:10).</p>",
    "28": "<p>The demon&#8217;s recognition of Jesus &#8212; &#8220;What do you want with me, Jesus, Son of the Most High God? I beg you, don&#8217;t torture me!&#8221; &#8212; is the supernatural knowledge of the defeated acknowledging the victor. The title &#8220;Son of the Most High God&#8221; is the same used by the Gentile girl in Acts 16:17 (&#8220;These men are servants of the Most High God&#8221;) &#8212; the universal divine title. The demons&#8217; acknowledgment of Jesus&#8217;s identity is the forced confession anticipating the universal acknowledgment of Phil 2:10&#8211;11: every knee will bow.</p>",
    "29": "<p>The demonic power that had repeatedly broken chains and driven the man into the wilderness is the type of the bondage from which Christ comes to free humanity. The chains and guards unable to hold the demoniac image the futility of human attempts to manage the problem of spiritual bondage without divine intervention. Isaiah 49:24&#8211;25 asks: &#8220;Can the prey be taken from the mighty man?&#8221; and answers: &#8220;But this is what the LORD says: Yes, captives will be taken from warriors, and plunder retrieved from the fierce.&#8221; Christ is the fulfillment of this promise.</p>",
    "30": "<p>&#8220;Legion&#8221; &#8212; the name of the many demons inhabiting the man &#8212; echoes the Roman military occupation (a Legion was approximately 6,000 soldiers); the name may carry both the literal sense (many demons) and a political-symbolic resonance. Christ&#8217;s authority over Legion demonstrates his authority over every power that oppresses humanity &#8212; spiritual and political. Col 2:15 describes the cross as the disarming of the powers and authorities, making a public spectacle of them: the Gerasene exorcism is a type of this cosmic disarmament.</p>",
    "31": "<p>The demons&#8217; begging not to be sent into the Abyss (<em>abyssos</em>) reveals their awareness of Christ&#8217;s eschatological authority. The Abyss (the bottomless pit of Rev 9:1&#8211;2; 20:1&#8211;3) is the place of the final confinement of demonic powers; Christ&#8217;s authority to consign them there is anticipated in his earthly ministry and accomplished definitively at the cross and resurrection (Rev 20:2&#8211;3: Satan bound and thrown into the Abyss). The demons&#8217; fear of the Abyss is the fear of their ultimate defeat.</p>",
    "32": "<p>The swine and their death in the lake: the entering of the demons into the unclean animals and their destruction images the judgment of the unclean order. The sea into which the pigs rush is the place of chaos and judgment; the destruction of the swine is a partial anticipation of the demons&#8217; ultimate consignment to the lake of fire (Rev 20:10). The unclean animals entering the chaotic water and perishing recalls the destruction of Pharaoh&#8217;s army in the Red Sea &#8212; the judgment of the oppressive power in the waters of death.</p>",
    "33": "<p>The entire herd rushing down the steep bank and drowning images the annihilation of the demonic forces &#8212; the destruction that the Gerasene man himself had been subjected to is now visited on the demons through the animals they inhabited. The same death the demons had visited on the man (exclusion, bondage, dwelling among the dead) is now their own fate. Christ accomplishes the reversal: what was done to the oppressed is done to the oppressor. This is the pattern of the cross itself &#8212; death swallowing Death (1 Cor 15:54&#8211;55; Hos 13:14).</p>",
    "34": "<p>The pig-tenders running to report &#8220;what had happened&#8221; to the town are the first witnesses of Jesus&#8217;s power in Gentile territory. Their report &#8212; like the shepherds&#8217; report at the nativity (2:17&#8211;18) &#8212; spreads the news of a transforming divine act beyond the immediate scene. The theme of witness-bearing to what Jesus has done is the foundation of the apostolic proclamation: the disciples and those who have been healed are the testimony to the living God&#8217;s intervention (Acts 1:8).</p>",
    "35": "<p>&#8220;They found the man from whom the demons had gone out, sitting at Jesus&#8217; feet, dressed and in his right mind&#8221; &#8212; the restored image of God in the healed man. Seated at Jesus&#8217;s feet in right mind (<em>s&#333;phronounta</em>, self-controlled, sober-minded) is the opposite of the demonic frenzy that had characterized him. This is the new creation image: the man reconstituted in his humanity at the feet of Christ, the one who restores the image of God (Col 3:10; Eph 4:24). The fear of the crowd mirrors Israel&#8217;s fear at Sinai &#8212; they were in the presence of the holy.</p>",
    "36": "<p>&#8220;Those who had seen it told the people how the demon-possessed man had been cured (<em>es&#333;th&#275;</em>, saved)&#8221; &#8212; the healing is described with the salvation-word <em>s&#333;z&#333;</em>. The eyewitness testimony establishes the reality of the transformation; the Gerasene exorcism is not reported as inner experience but as publicly verifiable change. The NT pattern of proclamation rests on this same logic: we proclaim what we have seen and heard (1 John 1:1&#8211;3). Christ&#8217;s saving acts are historical, testifiable, and transformative.</p>",
    "37": "<p>The region&#8217;s request for Jesus to leave &#8212; driven by fear rather than rejection &#8212; echoes the pattern of the rejected prophet: Elijah driven from Israel (1 Kgs 19:2), Isaiah&#8217;s message refused (Isa 53:3). Jesus&#8217;s peaceful compliance (he left) is itself part of his messianic pattern: he does not impose his presence but offers it and withdraws when refused. The judgment on those who reject him is not immediate punishment but the absence of the one who carries healing &#8212; the withdrawal of the Kingdom&#8217;s presence.</p>",
    "38": "<p>The healed man&#8217;s begging to go with Jesus reflects the natural desire of those whom Christ has delivered &#8212; to follow him wherever he goes (9:57). Jesus&#8217;s instruction to return home and testify is the commission given before the formal commissioning of the Twelve (9:1&#8211;6): the healed man becomes an informal apostle to the Gentile Decapolis. The pattern anticipates Acts: those delivered by Christ are sent to testify to their own community first.</p>",
    "39": "<p>&#8220;Return home and tell how much God has done for you&#8221; &#8212; and the man told &#8220;how much Jesus had done for him&#8221;: the implicit equation of Jesus with God. The man&#8217;s free indirect speech (Jesus said &#8220;God,&#8221; the man said &#8220;Jesus&#8221;) is Luke&#8217;s quiet Christological identification: what Jesus does is what God does; the man correctly identifies his healer as God acting in Jesus. This is the Johannine pattern (10:30: &#8220;I and the Father are one&#8221;) expressed in narrative form.</p>",
    "40": "<p>&#8220;A crowd welcomed him, for they were all expecting him&#8221; &#8212; the reception back on the Jewish side of the lake contrasts with the Gerasene request for him to leave. The expectation (<em>prosedok&#333;n</em>, they were waiting for him) is both the natural expectation of those who had seen his previous ministry and the deeper eschatological expectation of Israel waiting for the Lord (Isa 40:31; Ps 130:5&#8211;6). Christ&#8217;s return to the welcoming crowd images his eschatological return &#8212; expected, welcomed by those who have been watching.</p>",
    "41": "<p>Jairus, a synagogue leader, falling at Jesus&#8217;s feet represents the official Jewish leadership acknowledging Jesus&#8217;s authority &#8212; a relatively rare occurrence. The posture of prostration is the appropriate response to the presence of divine power (cf. Moses before the burning bush, Exod 3:5; Joshua before the commander of the LORD&#8217;s army, Josh 5:14). The desperate love of a father for his dying child drives the official past his social reservations &#8212; a theme of the divine Father&#8217;s love for his dying creation (John 3:16).</p>",
    "42": "<p>The only daughter about twelve years old who was dying &#8212; <em>monogen&#275;s</em> (only-born, unique), the same word used for the Nain widow&#8217;s son (7:12) and for the boy with the unclean spirit (9:38), and by John for Jesus himself (John 1:14,18; 3:16). The word is a deliberate Christological marker: Christ, the Father&#8217;s only-begotten, died so that the Father&#8217;s only-beloved children could be raised. The twelve-year-old girl and the woman who bled twelve years (v.43) bracket a double restoration of the &#8220;daughter of Israel.&#8221;</p>",
    "43": "<p>The woman with twelve years of hemorrhage is ritually unclean for the entire duration (Lev 15:25&#8211;27) &#8212; twelve years of exclusion from Temple worship, from community meals, from physical contact with others. Her condition is the image of Israel&#8217;s long-term uncleanness and exclusion from God&#8217;s full presence. Twelve years (the number of the tribes) frames her as a daughter of Israel, representing the whole people&#8217;s condition of defilement and need of cleansing &#8212; the cleansing that Ezek 36:25 promises (&#8220;I will sprinkle clean water on you, and you will be clean&#8221;).</p>",
    "44": "<p>&#8220;She touched the edge of his cloak, and immediately her bleeding stopped&#8221; &#8212; Mal 4:2 promises: &#8220;the sun of righteousness will rise with healing in its wings [<em>kanaph</em>, also: hem/edge of a garment]&#8221;. The LXX uses <em>pteryx</em> for the hem/wing, but the Hebrew <em>kanaph</em> deliberately connects the healing-hem of the Messianic Sun with the fringe of the prayer-shawl (Num 15:38&#8211;40). Those who touched the hem of Jesus&#8217;s garment were healed (Matt 14:36; Mark 6:56) &#8212; the Malachi prophecy finding its fulfillment in the touch of Christ&#8217;s garment-edge.</p>",
    "45": "<p>&#8220;Who touched me?&#8221; &#8212; Jesus&#8217;s awareness that power had gone out from him demonstrates his active, conscious exercise of healing power, not passive transmission. The disciples&#8217; confusion (the whole crowd is pressing around you) underscores that Jesus&#8217;s perception of the healing touch was supernatural knowledge. The public identification he seeks is for the woman&#8217;s benefit: she must be publicly acknowledged, not merely healed in secret. Christ&#8217;s healing is always toward full restoration &#8212; physical and social.</p>",
    "46": "<p>&#8220;I know that power has gone out from me&#8221; (<em>dynamis</em>) &#8212; the same word used for the Spirit&#8217;s power at the Annunciation (1:35) and for the power Jesus conferred on the Twelve (9:1). The self-aware expenditure of divine power in a healing act reveals the kenotic pattern of the incarnation: Christ gives himself for the healing of others, a self-expenditure that reaches its fullest expression at the cross, where he gives his life as a ransom for many (Mark 10:45).</p>",
    "47": "<p>The woman&#8217;s trembling declaration &#8220;in the presence of all the people&#8221; of why she touched him and how she was instantly healed is the public testimony that transforms a private healing into a communal witness. The fear (<em>trembling</em>) before Jesus mirrors the fear appropriate to divine presence (Luke 5:8&#8211;9; 8:25; 8:35). Her full declaration &#8212; both the act and the healing &#8212; is the pattern of the public confession of faith that the NT consistently requires (Rom 10:9&#8211;10: belief in the heart and confession with the mouth).</p>",
    "48": "<p>&#8220;Daughter, your faith has saved you (<em>ses&#333;ken</em>). Go in peace&#8221; &#8212; the salvation-word and the shalom-blessing together complete the restoration. Jesus addresses her as &#8220;Daughter&#8221; (<em>thygater</em>) &#8212; restoring her as a daughter of Abraham (13:16 uses this exact phrase for another healed woman), a full member of the covenant community. The faith that saves is not belief in a principle but trust in the person of Jesus; the peace he pronounces is the <em>shalom</em> of full reconciliation &#8212; with God, with community, with self.</p>",
    "49": "<p>&#8220;Your daughter is dead; don&#8217;t bother the teacher anymore&#8221; &#8212; the voice of despair and finality confronting Jesus&#8217;s way. Death is the ultimate human boundary that the messenger assumes cannot be crossed. The message &#8220;don&#8217;t bother the teacher anymore&#8221; is the logic of hopelessness in the face of death &#8212; the same logic that crucifixion was designed to communicate: this man is finished, done, dead. Jesus&#8217;s response to the death-messenger is the response of the resurrection: death does not set the final boundary.</p>",
    "50": "<p>&#8220;Don&#8217;t be afraid; just believe, and she will be healed (<em>s&#333;th&#275;setai</em>, saved)&#8221; &#8212; the salvation-word applied to resurrection from death. Jesus&#8217;s instruction to Jairus (fear &#8594; faith) is the eschatological instruction for every believer facing death: the resurrection of the dead is guaranteed by Christ&#8217;s own resurrection (1 Cor 15:20: &#8220;Christ has indeed been raised from the dead, the firstfruits of those who have fallen asleep&#8221;). The &#8220;just believe&#8221; in the face of death is the defining posture of resurrection faith.</p>",
    "51": "<p>The restriction to Peter, John, James, and the girl&#8217;s parents echoes the pattern of Moses on Sinai (only Moses and the elders ascended) and the Transfiguration (only the three on the mountain). The intimate restriction preserves the mystery of the resurrection-sign from premature public disclosure &#8212; part of the Lukan pattern of Jesus controlling the revelation of his messianic identity. The resurrection of the girl is given to a restricted circle; the resurrection of Jesus will be proclaimed to the world.</p>",
    "52": "<p>&#8220;She is not dead but asleep&#8221; &#8212; the redefinition of death from the perspective of resurrection. Jesus uses the sleep metaphor that Paul will employ in 1 Thess 4:13&#8211;14 (&#8220;we do not want you to be uninformed about those who sleep in death&#8221;) and John 11:11&#8211;14 (&#8220;our friend Lazarus has fallen asleep; but I am going there to wake him up&#8221;). For those in Christ, physical death is sleep from which awakening is certain; the mourners&#8217; laughter exposes the gap between the secular view of death&#8217;s finality and Christ&#8217;s authority over it.</p>",
    "53": "<p>&#8220;They laughed at him, knowing that she was dead&#8221; &#8212; the cynical certainty of death&#8217;s finality confronting the resurrection claim. The laughter parallels the incredulity that met the resurrection proclamation (Acts 17:32: &#8220;when they heard about the resurrection of the dead, some of them sneered&#8221;). The crowd that laughs at Christ&#8217;s redefinition of death is excluded from witnessing the miracle; the restricted circle of faith (v.51) alone is present for the resurrection-sign. Faith opens to resurrection; unbelief remains outside.</p>",
    "54": "<p>&#8220;My child, get up!&#8221; (<em>hē pais, egeire</em>) &#8212; the resurrection command. <em>Egeir&#333;</em> (to raise, to get up) is the same verb used for the resurrection of Jesus throughout the NT (Matt 28:6; Rom 4:25; 1 Cor 15:4). The verbal parallel between Jesus raising the girl and Jesus&#8217;s own resurrection is deliberate: the same authority that commands the dead girl to rise is the authority at work in the Father raising the Son (John 10:17&#8211;18; 11:25). The short, direct command &#8212; no prayer, no labored effort, just authoritative speech &#8212; reveals the one who is himself the resurrection and the life (John 11:25).</p>",
    "55": "<p>&#8220;Her spirit returned, and at once she stood up&#8221; &#8212; the <em>pneuma</em> (spirit/life-breath) returning at the resurrection command echoes Gen 2:7 (God breathing life into Adam) and Ezek 37:5,10 (the breath entering the dry bones). Christ as the one who restores the spirit/breath is the eschatological fulfillment of the divine life-giving that began at creation. The instruction to give her something to eat demonstrates the reality of the bodily resurrection &#8212; this is not a ghost but a genuinely revived person &#8212; anticipating Jesus&#8217;s own eating after his resurrection (24:41&#8211;43).</p>",
    "56": "<p>The parents&#8217; astonishment and Jesus&#8217;s instruction not to tell anyone complete the mystery pattern of the chapter: the resurrection-sign is real but not yet for public proclamation. The silence Jesus commands is the silence of the messianic mystery not yet ready to be fully revealed &#8212; the full meaning of &#8220;Christ and him crucified&#8221; (1 Cor 2:2) awaits the cross and resurrection to be understood. The whole chapter (word-sowing, storm-stilling, demonic deliverance, double-healing and resurrection) is a portrait of Christ&#8217;s comprehensive sovereignty: over the word, nature, the demonic, disease, and death.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, DATA)
    merge_comm(existing, FILL_CH8)
    save_comm('mkt-christ', 'luke', existing)
    total = sum(len(v) for v in existing.values())
    print(f"Luke mkt-christ: {len(existing)} chapters, {total} verses written.")

if __name__ == '__main__':
    main()
